from flask import Flask, request, Response
from sqlalchemy import create_engine, Column, Integer, String
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker

from models import Account, Session, Base

app = Flask(__name__)

database_url = "sqlite:///state.db"

Base.metadata.create_all(create_engine(database_url))
Session = sessionmaker(bind=create_engine(database_url))

@app.route('/transfer', methods=['POST'])
def transfer_funds():
    data = request.json
    logging.error(f"Received transfer request: {data}")

    amount = data['amount']
    sender_key = data['sender_key']
    recipient_key = data['recipient_key']

    with Session() as session:
        sender = session.query(Account).filter_by(key=sender_key).one()
        recipient = session.query(Account).filter_by(key=recipient_key).one()

        # 1. Check sender has funds available
        if sender.balance < amount:
            return Response(response=json.dumps({"message": "Insufficient funds"}), status=400,
                            content_type='application/json')

        # 2. Deduct funds from sender
        sender.balance -= amount
        session.add(sender)

        # 3. Add funds to recipient
        recipient.balance += amount
        session.add(recipient)

        session.commit()

    return Response(response=json.dumps({"message": f"Transferred {amount} from {sender_key} to {recipient_key}", "success": True}), status=200,
                    content_type='application/json')


@app.route('/', methods=['GET'])
def index():
    return Response(response=json.dumps({"status": "OK"}), status=200, content_type="application/json")


@app.route('/balances', methods=['GET'])
def get_balances():
    with Session() as session:
        accounts = session.query(Account).all()
        result = {account.key: account.balance for account in accounts}

    return Response(response=json.dumps(result), status=200, content_type='application/json')


def seed_accounts() -> None:
    """Create the initial accounts and balances."""
    with Session() as session:
        session.add_all(
            [
                Account(key="A", balance=1000, currency="USD"),
                Account(key="B", balance=1000, currency="USD")
            ]
        )
        session.commit()


def reset_accounts() -> None:
    """Reset balances back to seed values."""
    with Session() as session:
        session.execute("UPDATE account SET balance = 1000")
        session.commit()


def get_money_supply() -> int:
    """Returns the total number of USD in the system. Invariant: should always be 2000."""
    with Session() as session:
        accounts = session.query(Account).all()
        return sum([account.balance for account in accounts])


